"use client";

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, 
  ArrowLeft, 
  Calendar, 
  Wallet, 
  PieChart, 
  Percent, 
  Loader2,
  AlertCircle,
  Clock
} from 'lucide-react';

// --- INTERFEJSY ---
interface TimelineItem {
  month: number;
  totalValue: number;
  accumulatedProfit: number;
}

interface ObliczeniaWynik {
  daily: number;
  weekly: number;
  monthly: number;
  yearly: number;
  total: number;
  duration: string; 
  timeline: TimelineItem[];
}

interface Obligacja {
  symbol: string;
  oprocentowaniePierwszyRok: number;
  okresLata: number;
  kapitalizacja: boolean;
}

// --- KOMPONENTY WYKRESÓW SVG (BEZ ZEWNĘTRZNYCH BIBLIOTEK) ---

const SimplePieChart = ({ capital, profit, formatPLN }: { capital: number, profit: number, formatPLN: (v: number) => string }) => {
  const total = capital + profit;
  const capitalPercent = total > 0 ? capital / total : 1;
  const x = Math.cos(2 * Math.PI * capitalPercent);
  const y = Math.sin(2 * Math.PI * capitalPercent);
  const largeArcFlag = capitalPercent > 0.5 ? 1 : 0;

  const pathData = [
    `M 1 0`,
    `A 1 1 0 ${largeArcFlag} 1 ${x} ${y}`,
    `L 0 0`,
  ].join(' ');

  return (
    <div className="flex flex-col items-center justify-center h-full">
      <svg viewBox="-1.1 -1.1 2.2 2.2" className="w-40 h-40 -rotate-90 drop-shadow-sm">
        <circle cx="0" cy="0" r="1" fill="#10B981" />
        <path d={pathData} fill="#0071E3" />
        <circle cx="0" cy="0" r="0.6" fill="white" />
      </svg>
      <div className="mt-6 space-y-2 w-full max-w-[200px]">
        <div className="flex justify-between items-center text-[10px] uppercase font-bold tracking-wider">
          <div className="flex items-center gap-2">
            <div className="w-2.5 h-2.5 rounded-full bg-[#0071E3]"></div>
            <span className="text-gray-400">Wkład</span>
          </div>
          <span className="text-gray-900">{formatPLN(capital)}</span>
        </div>
        <div className="flex justify-between items-center text-[10px] uppercase font-bold tracking-wider">
          <div className="flex items-center gap-2">
            <div className="w-2.5 h-2.5 rounded-full bg-[#10B981]"></div>
            <span className="text-gray-400">Zysk Netto</span>
          </div>
          <span className="text-gray-900">{formatPLN(profit)}</span>
        </div>
      </div>
    </div>
  );
};

const SimpleAreaChart = ({ data, formatPLN }: { data: TimelineItem[], formatPLN: (v: number) => string }) => {
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
  const padding = { top: 20, right: 10, bottom: 30, left: 10 };
  const width = 1000;
  const height = 300;

  if (!data || data.length === 0) return null;

  const values = data.map(d => d.totalValue);
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = max - min || 1;

  const getX = (index: number) => padding.left + (index * (width - padding.left - padding.right)) / (data.length - 1);
  const getY = (value: number) => height - padding.bottom - ((value - min) * (height - padding.top - padding.bottom)) / range;

  const points = data.map((d, i) => `${getX(i)},${getY(d.totalValue)}`).join(' ');
  const areaPoints = `${getX(0)},${height - padding.bottom} ${points} ${getX(data.length - 1)},${height - padding.bottom}`;

  return (
    <div className="relative w-full h-full group">
      <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full overflow-visible">
        <defs>
          <linearGradient id="chartGradient" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#0071E3" stopOpacity="0.2" />
            <stop offset="100%" stopColor="#0071E3" stopOpacity="0" />
          </linearGradient>
        </defs>
        {[0, 0.5, 1].map((p) => {
          const y = padding.top + p * (height - padding.top - padding.bottom);
          return <line key={p} x1={padding.left} y1={y} x2={width - padding.right} y2={y} stroke="#F5F5F7" strokeWidth="2" />;
        })}
        <polyline points={areaPoints} fill="url(#chartGradient)" />
        <polyline points={points} fill="none" stroke="#0071E3" strokeWidth="4" strokeLinejoin="round" strokeLinecap="round" />
        {data.map((d, i) => (
          <g key={i} onMouseEnter={() => setHoveredIndex(i)} onMouseLeave={() => setHoveredIndex(null)}>
            <rect x={getX(i) - 10} y={0} width={20} height={height} fill="transparent" className="cursor-pointer" />
            {hoveredIndex === i && <circle cx={getX(i)} cy={getY(d.totalValue)} r={8} fill="#0071E3" />}
          </g>
        ))}
      </svg>
      {hoveredIndex !== null && (
        <div 
          className="absolute z-10 bg-white p-3 border border-gray-100 shadow-xl rounded-xl pointer-events-none"
          style={{ 
            left: `${(getX(hoveredIndex) / width) * 100}%`, 
            top: `${(getY(data[hoveredIndex].totalValue) / height) * 100}%`,
            transform: 'translate(-50%, -120%)'
          }}
        >
          <p className="text-[10px] font-bold text-gray-400 uppercase">Miesiąc {data[hoveredIndex].month}</p>
          <p className="text-sm font-bold text-blue-600">{formatPLN(data[hoveredIndex].totalValue)}</p>
        </div>
      )}
    </div>
  );
};

// --- KOMPONENTY POMOCNICZE ---

function ResultWidget({ label, value }: { label: string, value: string }) {
    return (
        <div className="bg-white rounded-[24px] p-6 shadow-sm border border-gray-100 flex flex-col justify-center">
            <span className="text-[0.75rem] font-bold text-gray-400 uppercase tracking-widest mb-2">
                {label}
            </span>
            <span className="text-2xl font-bold text-gray-900 tracking-tight">
                {value}
            </span>
        </div>
    )
}

function WynikGlownyKafelek({ wyniki, formatPLN }: { wyniki: ObliczeniaWynik, formatPLN: (value: number | undefined) => string }) {
    const [isOpen, setIsOpen] = useState(false);
    const gradientStyle = { background: 'linear-gradient(135deg, #0071E3 0%, #00C7BE 100%)' };

    return (
        <div className="w-full">
            <div 
                style={{ ...gradientStyle, transition: 'all 0.3s ease' }}
                className="p-6 md:p-8 rounded-[2rem] text-white shadow-xl flex flex-col md:flex-row justify-between items-start md:items-center cursor-pointer hover:shadow-2xl hover:scale-[1.01] transform"
                onClick={() => setIsOpen(!isOpen)}
            >
                <div className="flex-grow mb-4 md:mb-0">
                    <p className="opacity-90 text-base md:text-lg mb-1 font-medium">
                        Zysk całkowity "na rękę" (netto)
                    </p>
                    <h3 className="text-4xl md:text-5xl font-extrabold tracking-tight">
                        {formatPLN(wyniki.total)}
                    </h3>
                </div>
                <div className="flex items-center space-x-4">
                    <div className="bg-white/20 px-4 py-2 rounded-xl backdrop-blur-sm text-sm font-semibold whitespace-nowrap">
                        <span className="flex items-center gap-2"><Clock size={16} /> Okres: {wyniki.duration}</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

// --- GŁÓWNA STRONA ---

export default function KalkulatorPage() {
  const [kwota, setKwota] = useState<number | ''>(1000);
  const [wybranySymbol, setWybranySymbol] = useState<string>('');
  const [listaObligacji, setListaObligacji] = useState<Obligacja[]>([]);
  const [wyniki, setWyniki] = useState<ObliczeniaWynik | null>(null); 
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [loadingObligacje, setLoadingObligacje] = useState(true);

  const BACKEND_URL = process.env.NEXT_PUBLIC_BACKEND_URL || "http://localhost:8080/api";

  useEffect(() => {
    const fetchObligacje = async () => {
      try {
        const response = await fetch(`${BACKEND_URL}/obligacje`);
        if (!response.ok) throw new Error('Nie udało się pobrać listy obligacji.');
        const data: Obligacja[] = await response.json();
        setListaObligacji(data);
        if (data.length > 0) setWybranySymbol(data[0].symbol);
      } catch (e) {
        setError('Brak połączenia z backendem. Upewnij się, że serwer działa.');
      } finally {
        setLoadingObligacje(false);
      }
    };
    fetchObligacje();
  }, [BACKEND_URL]);

  const handleOblicz = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setWyniki(null);

    if (!kwota || Number(kwota) <= 0) {
      setError('Podaj poprawną kwotę inwestycji.');
      return;
    }
    setLoading(true);
    try {
      const url = `${BACKEND_URL}/calc?kwota=${kwota}&symbol=${wybranySymbol}`;
      const response = await fetch(url);
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Błąd serwera');
      }
      const data: ObliczeniaWynik = await response.json();
      setWyniki(data);
    } catch (e: any) {
      setError(e.message || 'Wystąpił nieznany błąd połączenia.');
    } finally {
      setLoading(false);
    }
  };

  const formatPLN = (value: number | undefined) => {
    if (value === undefined || isNaN(value)) return '-';
    return new Intl.NumberFormat('pl-PL', { style: 'currency', currency: 'PLN', minimumFractionDigits: 2 }).format(value);
  };

  const wybranaObligacjaInfo = listaObligacji.find(o => o.symbol === wybranySymbol);

  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] pb-20 font-sans antialiased">
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-xl border-b border-gray-100 px-6 py-4 flex justify-center">
        <div className="w-full max-w-5xl flex justify-between items-center">
            <a href="/" className="flex items-center gap-2 text-gray-500 hover:text-black transition-colors no-underline font-semibold text-sm">
                <ArrowLeft size={18} /> Powrót
            </a>
            <span className="font-bold text-xl tracking-tight flex items-center gap-2">
                <TrendingUp size={22} className="text-[#0071E3]" /> Kalkulator
            </span>
            <div className="w-10"></div> 
        </div>
      </nav>

      <div className="max-w-4xl mx-auto px-6 pt-12">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-extrabold tracking-tight mb-3">Symulacja zysków</h1>
          <p className="text-lg text-gray-500 font-medium">Precyzyjne obliczenia uwzględniające podatek Belki.</p>
        </div>

        <div className="bg-white p-8 rounded-[32px] shadow-sm border border-gray-100 mb-8">
          {loadingObligacje ? (
              <div className="py-12 flex flex-col items-center justify-center text-gray-400">
                <Loader2 className="animate-spin mb-3" size={32} />
                <p className="font-medium">Pobieranie oferty z API...</p>
              </div>
          ) : (
          <form onSubmit={handleOblicz} className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div>
                <label className="block text-[0.75rem] font-bold uppercase tracking-widest text-gray-400 mb-3 ml-1">Kwota inwestycji (PLN)</label>
                <div className="relative">
                  <Wallet size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input
                    type="number"
                    value={kwota}
                    onChange={(e) => setKwota(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full bg-[#F5F5F7] border-none rounded-2xl py-4 pl-12 pr-4 text-xl font-bold focus:ring-2 focus:ring-[#0071E3]/20 transition-all outline-none"
                  />
                </div>
              </div>
              <div>
                <label className="block text-[0.75rem] font-bold uppercase tracking-widest text-gray-400 mb-3 ml-1">Rodzaj Obligacji</label>
                <div className="relative">
                  <PieChart size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                  <select
                    value={wybranySymbol}
                    onChange={(e) => setWybranySymbol(e.target.value)}
                    className="w-full bg-[#F5F5F7] border-none rounded-2xl py-4 pl-12 pr-4 text-xl font-bold focus:ring-2 focus:ring-[#0071E3]/20 transition-all outline-none appearance-none cursor-pointer"
                  >
                    {listaObligacji.map(o => <option key={o.symbol} value={o.symbol}>{o.symbol}</option>)}
                  </select>
                </div>
              </div>
            </div>

            {wybranaObligacjaInfo && (
              <div className="p-6 rounded-2xl bg-[#F5F5F7] flex flex-wrap gap-8 items-center justify-between border border-gray-100">
                <div className="flex items-center gap-3">
                  <Percent size={18} className="text-[#0071E3]" />
                  <span className="font-medium text-gray-700">Oprocentowanie: <strong className="text-gray-900">{wybranaObligacjaInfo.oprocentowaniePierwszyRok}%</strong></span>
                </div>
                <div className="flex items-center gap-3">
                    <Calendar size={18} className="text-[#0071E3]" />
                    <span className="font-medium text-gray-700"> Zapadalność: <strong className="text-gray-900">
                          {wybranaObligacjaInfo.okresLata === 0 ? "3 miesiące" : wybranaObligacjaInfo.okresLata === 1
                            ? "1 rok" : `${wybranaObligacjaInfo.okresLata} lata`}
                    </strong></span>
                </div>
              </div>
            )}

            <button type="submit" disabled={loading} className="w-full bg-[#0071E3] text-white py-5 rounded-2xl font-bold text-xl shadow-lg shadow-[#0071E3]/20 hover:bg-[#005bb5] transition-all flex items-center justify-center gap-3 active:scale-[0.98]">
              {loading ? <><Loader2 className="animate-spin" size={24}/> Obliczanie...</> : 'Oblicz potencjalny zysk'}
            </button>

            {error && (
              <div className="bg-red-50 border border-red-100 rounded-2xl p-5 flex items-center gap-4 text-red-600">
                  <AlertCircle size={24} />
                  <p className="font-bold text-sm">{error}</p>
              </div>
            )}
          </form>
          )}
        </div>

        {wyniki && (
          <div className="mt-12 animate-in fade-in slide-in-from-bottom-8 duration-700 space-y-10">
            <h2 className="text-2xl font-extrabold tracking-tight px-2">Analiza wyników</h2>
            
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <ResultWidget label="Zysk Dzienny" value={formatPLN(wyniki.daily)} />
               <ResultWidget label="Zysk Miesięczny" value={formatPLN(wyniki.monthly)} />
               <ResultWidget label="Zysk Roczny (śr.)" value={formatPLN(wyniki.yearly)} />
               <div className="col-span-1 md:col-span-3">
                   <WynikGlownyKafelek wyniki={wyniki} formatPLN={formatPLN} />
               </div>
            </div>

            {/* SEKCJA WYKRESÓW (BENTO GRID) */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-stretch">
                <div className="md:col-span-2 bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex flex-col">
                    <div className="flex justify-between items-center mb-10">
                        <h3 className="text-lg font-bold">Progresja kapitału</h3>
                        <div className="px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-widest">Wzrost</div>
                    </div>
                    <div className="h-[300px] w-full mt-auto">
                        <SimpleAreaChart data={wyniki.timeline} formatPLN={formatPLN} />
                    </div>
                </div>
                <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex flex-col items-center">
                    <div className="w-full flex justify-between items-center mb-10">
                        <h3 className="text-lg font-bold">Struktura</h3>
                        <PieChart className="text-gray-300" size={20} />
                    </div>
                    <div className="flex-grow flex items-center justify-center">
                        <SimplePieChart capital={Number(kwota)} profit={wyniki.total} formatPLN={formatPLN} />
                    </div>
                </div>
            </div>

            {/* HARMONOGRAM (POPRAWIONA CZYTELNOŚĆ) */}
            <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
                <div className="p-8 border-b border-gray-100 bg-gray-50/30">
                    <h3 className="text-lg font-bold">Harmonogram wzrostu</h3>
                    <p className="text-sm text-gray-500 mt-1">Szczegółowe zestawienie miesiąc po miesiącu</p>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50 text-[0.65rem] font-bold uppercase tracking-widest text-gray-400">
                                <th className="px-8 py-5 border-b border-gray-100">Miesiąc</th>
                                <th className="px-8 py-5 border-b border-gray-100">Stan Konta</th>
                                <th className="px-8 py-5 border-b border-gray-100 text-right">Zysk Netto</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            <tr className="bg-blue-50/30 group">
                                <td className="px-8 py-5 text-gray-400 font-medium italic">Start</td>
                                <td className="px-8 py-5 font-semibold text-gray-900">{formatPLN(Number(kwota))}</td>
                                <td className="px-8 py-5 text-right text-gray-400">—</td>
                            </tr>
                            {wyniki.timeline.map((item) => (
                                <tr key={item.month} className="hover:bg-gray-50/50 transition-colors group">
                                    <td className="px-8 py-5 font-medium text-gray-500 group-hover:text-gray-900">{item.month}</td>
                                    <td className="px-8 py-5 font-bold text-gray-900 group-hover:text-blue-600 transition-colors">
                                        {formatPLN(item.totalValue)}
                                    </td>
                                    <td className="px-8 py-5 text-right text-emerald-600 font-extrabold group-hover:scale-105 transition-transform origin-right">
                                        +{formatPLN(item.accumulatedProfit)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}